// ============================================================================
// MAIN
// ============================================================================

function expandPostContent(post, locale, expansionHtml) {
  const c = post.content[locale];
  if (!c || typeof c !== "string") return false;
  if (c.includes(`${SENTINEL}-${post.slug}`)) return false; // already expanded
  const sentinelTag = `<${SENTINEL}-${post.slug} />`;
  const relatedMarker = `<aside data-related-links="true"`;
  const idx = c.indexOf(relatedMarker);
  if (idx < 0) {
    // append at end if no related block
    post.content[locale] = c + sentinelTag + expansionHtml;
  } else {
    // insert before related block
    post.content[locale] = c.slice(0, idx) + sentinelTag + expansionHtml + c.slice(idx);
  }
  return true;
}

function main() {
  const raw = fs.readFileSync(POSTS_PATH, "utf8");
  const posts = JSON.parse(raw);
  let expandedCount = 0;
  let addedTulum = false;

  // Add Tulum if not present
  if (!posts.find((p) => p.slug === TULUM_POST.slug)) {
    posts.push(TULUM_POST);
    addedTulum = true;
  }

  // Expand thin posts
  for (const post of posts) {
    const exp = EXPANSIONS[post.slug];
    if (!exp) continue;
    let mut = false;
    for (const locale of ["es", "en"]) {
      if (exp[locale] && expandPostContent(post, locale, exp[locale])) mut = true;
    }
    // Bump readingTime if expanded (each lang adds ~600-1000 words ≈ +4 min)
    if (mut) {
      post.readingTime = (post.readingTime || 8) + 5;
      post.updatedDate = TODAY;
      expandedCount++;
    }
  }

  fs.writeFileSync(POSTS_PATH, JSON.stringify(posts, null, 2) + "\n");
  console.log(`Tulum added: ${addedTulum}. Expanded posts: ${expandedCount}/${Object.keys(EXPANSIONS).length}.`);
  console.log(`Total posts: ${posts.length}.`);
}

main();
